html,
body {
  width: 100%;
  min-height: 100%;
  max-width: 100%;
  overflow-x: hidden;
}

body {
  margin: 0;
  background: #07080b;
  font-family: var(--font-sans), ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, "Apple Color Emoji", "Segoe UI Emoji";
  letter-spacing: -0.01em;
  font-feature-settings: "ss01" 1, "ss02" 1, "cv11" 1;
}

.page {
  min-height: 100%;
  overflow-x: hidden;
  display: flex;
  flex-direction: column;

  background-color: var(--bg-deep);
  background-image:
    radial-gradient(circle at 12% 12%, rgba(95, 134, 255, 0.16) 0%, transparent 48%),
    radial-gradient(circle at 88% 82%, rgba(20, 24, 40, 0.9) 0%, transparent 55%),
    linear-gradient(145deg, #07080b 0%, #040407 55%, #000 100%);
  color: var(--text-primary);
}

@media (min-width: 1025px) {
  .nav {
    backdrop-filter: none;
    -webkit-backdrop-filter: none;
    background: rgba(5, 6, 10, 0.82);
  }

  .spatialBackdrop {
    backdrop-filter: none;
    -webkit-backdrop-filter: none;
    background: linear-gradient(135deg, rgba(255, 255, 255, 0.03) 0%, rgba(0, 0, 0, 0.72) 100%);
  }

  .node {
    backdrop-filter: none;
    -webkit-backdrop-filter: none;
    background: rgba(255, 255, 255, 0.04);
  }
}

